{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "./candidate-change.schema.json",
  "title": "Candidate change",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "schema_version",
    "record_type",
    "id",
    "name",
    "lifecycle_status",
    "submitted_at",
    "scope",
