    "name": {
      "type": "string"
    },
    "summary": {
      "type": "string"
    },
    "lifecycle_status": {
      "enum": [
        "draft",
        "submitted",
        "in_review",
        "needs_revision",
        "accepted",
        "rejected",
        "applied"
      ]
    },
    "submitted_at": {
      "$ref": "./common.schema.json#/$defs/dateTime"
    },
    "scope": {
      "type": "object",
      "additionalProperties": false,
